121: // Convert golang errors to status result errors that can be returned to a client
122: func AsErrorResult(err error) *resourcepb.ErrorResult {
123: 	if err == nil {
124: 		return nil
125: 	}
126: 
127: 	var apistatus apierrors.APIStatus
128: 	if errors.As(err, &apistatus) {
129: 		s := apistatus.Status()
130: 		res := &resourcepb.ErrorResult{
131: 			Message: s.Message,
132: 			Reason:  string(s.Reason),
133: 			Code:    s.Code,
134: 		}
135: 		if s.Details != nil {
136: 			res.Details = &resourcepb.ErrorDetails{
137: 				Group:             s.Details.Group,
138: 				Kind:              s.Details.Kind,
139: 				Name:              s.Details.Name,
140: 				Uid:               string(s.Details.UID),
141: 				RetryAfterSeconds: s.Details.RetryAfterSeconds,
142: 			}
143: 			for _, c := range s.Details.Causes {
144: 				res.Details.Causes = append(res.Details.Causes, &resourcepb.ErrorCause{
145: 					Reason:  string(c.Type),
146: 					Message: c.Message,
147: 					Field:   c.Field,
148: 				})
149: 			}
150: 		}
151: 		return res
152: 	}
153: 
154: 	code := 500
155: 
156: 	st, ok := grpcstatus.FromError(err)
157: 	if ok {
158: 		code = runtime.HTTPStatusFromCode(st.Code())
159: 	}
160: 
161: 	return &resourcepb.ErrorResult{
162: 		Message: err.Error(),
163: 		Code:    int32(code),
164: 	}
165: }
