197: func HandleQueueError[T any](err error, makeResp func(*resourcepb.ErrorResult) *T) (*T, error) {
198: 	if errors.Is(err, scheduler.ErrTenantQueueFull) {
199: 		return makeResp(NewTooManyRequestsError("tenant queue is full, please try again later")), nil
200: 	}
201: 	return makeResp(AsErrorResult(err)), nil
